@module DAG  src=DAG.lua  loc=1919  sha=d013d39  mode=namespace  self=DAG

# Invariants & contracts
  @invariant  DAG.validate is pure; derivations live on DAG.compile's ctx  @ 6
  @invariant  REAPER tracks are always stereo; audio I/O is a count of stereo pairs, never channels  @ 7
  @invariant  every user-graph node carries node.ports={audio={…},midi={ins,outs}} at construction  @ 8
  @invariant  fx midi: JSFX ports come from midirecv/midisend scan; native fx get {1,1}.  @ 9
  @invariant  master is a singleton node (id='master'); ports.audio.ins is an explicit integer port count (default 1); no audio outs, no MIDI; terminal-only (never `from`)  @ 10
  @invariant  fx nodes carry busAware; wm:addFxNode and DAG.validate refuse true  @ 13
  @invariant  fxId is nil until materialised; stamped into the node after TrackFX_AddByName succeeds  @ 14
  @invariant  edge ops ride as metadata; gain on a sole send-wire folds onto send volume, else CU  @ 17
  @invariant  node.split (fx only): seeds 'split:'..id into srcSet; node+cone get own class/track  @ 19
  @invariant  a split-tagged class never absorbs  @ 20
  @invariant  signal-bearing bus seeds 'bus:'..id; marker never spreads — bus sits alone in its class  @ 21
  @invariant  bus classes absorb in neither direction; a dangling bus is inert (empty srcSet)  @ 22
  @invariant  a class with no audio parents and a lone source-direct midi parent absorbs onto it  @ 23
  @invariant  busses below 2x2 splice out at compile; crossings become direct edges at product gain  @ 24
  @invariant  srcSet unions node.split with derived master-min split markers  @ 25

# Shapes
  @shape  userGraph = { nodes = {[id]=userNode}, edges = edge[] }  -- node ids are rm guids (read era)  @ 11
  @shape  userNode = { kind='source'|'fx'|'master'|'bus', pos={x,y}, ports={audio={ins,outs,inNames?,outNames?}, midi={ins,outs}}, trackId?=string, fxIdent?=string, fxDisplay?=string, fxId?=string, busAware?=bool, split?=true, orient?='V'|'H' }  -- bus: synthetic id, no source/fx; its summing track's guid lives on the bus record, not the node  @ 12
  @shape  edge = { type='audio'|'midi', from=id, fromPort=nil|portIdx, to=id, toPort=nil|portIdx, ops?={gain?=number}, primary?=true }  @ 16
  @shape  synthNode = { kind='fx', fxIdent=CU_IDENT, fxId?=string, params=table, originNode?=string, originSide?='in'|'out', originConsumer?=string, originTrackKey?=string, inputEdges?=int[] }  @ 26
  @shape  outWire = { from=id, fromPort?=int, to=trackKey, toNode=id, toPort?=int, type='audio'|'midi', gain?=number }  @ 28
  @shape  intraConn = { from=id, fromPort?=int, to=id, toPort?=int, type='audio'|'midi' }  @ 29
  @shape  trackSpec = { trackKind='sourceTrack'|'newTrack'|'master'|'scratch', trackId?=string, fxOrder=id[], mainSend=bool,  @ 30
  @shape  mainSendGain?=number, parentFeed?={from=id, fromPort?=int, toNode=id, toPort?=int, sink=trackKey},  @ 31
  @shape  synthNodes?={[cuId]=synthNode}, outWires=outWire[], intraConns=intraConn[],  @ 32
  @shape  pipeMidi?={{from=id, consumer=id},...} }  -- parentFeed.sink is MASTER or folder parent trackKey; pipeMidi = un-gateable crossings  @ 33
  @shape  targetTracks = { [trackKey] = trackSpec }  @ 34
  @shape  allocatedSend = { to=trackKey, type='audio'|'midi', gain?=number, srcChan=int, dstChan=int, preFx?=true }; audio src/dstChan are (pair-1)*2, midi are bus 0..127; preFx marks a raw-source-origin (pre-FX) send  @ 36
  @shape  allocatedPinMap = { [fxId] = { ins={[port]={pair,...}}, outs={[port]={pair,...}} } }  @ 37
  @shape  allocatedTracks = { [trackKey] = { trackKind=..., trackId?=..., fxOrder=..., mainSend=..., mainSendGain?=..., sends=allocatedSend[], fxMidiBus?={ [fxId]={inBus,outBus} } (native fx only), pinMaps=allocatedPinMap, nchan=int, mainSendOffs?=int, bracketNodes?={ [bracketId]=synthNode } } }; see docs/DAG.md § allocate for the allocator + bracket model.  @ 38
  @shape  component = { nodes=id[] (sorted), reason=nil|'feedback'|'busAware' }  @ 170
  @shape  spliceProv = { parts = {[splicedIdx]=authoredIdx[]} }  -- a product edge lists every authored tap it folds  @ 1048
  @shape  flow = { type, from?, fromPort?, fromSlot?, to?, toPort?, toSlot?, escape?='send'|'feed', sendIdx?, inc?=incoming entry }  @ 1278

